17	// RBTDRM — colophon manifest verification for theurge
18	
19	/// Colophon consts — single definition per String Boundary Discipline.
20	/// Each names the bash tabtarget colophon theurge invokes for that operation.
21	
22	// Crucible lifecycle colophons (nameplate-scoped)
23	pub const RBTDRM_COLOPHON_CHARGE: &str = "rbw-cC";
24	pub const RBTDRM_COLOPHON_QUENCH: &str = "rbw-cQ";
25	pub const RBTDRM_COLOPHON_WRIT: &str = "rbw-cw";
26	pub const RBTDRM_COLOPHON_FIAT: &str = "rbw-cf";
27	pub const RBTDRM_COLOPHON_BARK: &str = "rbw-cb";
28	
29	// Foundry colophons (global — no nameplate imprint)
30	pub const RBTDRM_COLOPHON_ORDAIN: &str = "rbw-fO";
31	pub const RBTDRM_COLOPHON_ABJURE: &str = "rbw-fA";
32	pub const RBTDRM_COLOPHON_TALLY: &str = "rbw-ft";
33	pub const RBTDRM_COLOPHON_KLUDGE: &str = "rbw-fk";
34	pub const RBTDRM_COLOPHON_VOUCH: &str = "rbw-fV";
35	pub const RBTDRM_COLOPHON_SUMMON: &str = "rbw-fs";
36	pub const RBTDRM_COLOPHON_PLUMB_FULL: &str = "rbw-fpf";
37	pub const RBTDRM_COLOPHON_PLUMB_COMPACT: &str = "rbw-fpc";
38	
39	// Image colophons (global — no nameplate imprint)
40	pub const RBTDRM_COLOPHON_WREST: &str = "rbw-iw";
41	pub const RBTDRM_COLOPHON_REKON: &str = "rbw-ir";
42	pub const RBTDRM_COLOPHON_JETTISON: &str = "rbw-iJ";
43	
44	// Crucible active check (param1 channel — nameplate as argument)
45	pub const RBTDRM_COLOPHON_CRUCIBLE_ACTIVE: &str = "rbw-cic";
46	
47	// Access probe colophon (imprint-scoped by role)
48	pub const RBTDRM_COLOPHON_ACCESS_PROBE: &str = "rbtd-ap";
49	
50	// Handbook display colophons — one symbolic ref per RBZ_* zipper constant.
51	// Onboarding group (8)
52	pub const RBTDRM_COLOPHON_ONBOARD_START_HERE: &str = "rbw-o";
53	pub const RBTDRM_COLOPHON_ONBOARD_CRASH_COURSE: &str = "rbw-Occ";
54	pub const RBTDRM_COLOPHON_ONBOARD_CRED_RETRIEVER: &str = "rbw-Ocr";
55	pub const RBTDRM_COLOPHON_ONBOARD_CRED_DIRECTOR: &str = "rbw-Ocd";
56	pub const RBTDRM_COLOPHON_ONBOARD_FIRST_CRUCIBLE: &str = "rbw-Ofc";
57	pub const RBTDRM_COLOPHON_ONBOARD_DIR_FIRST_BUILD: &str = "rbw-Odf";
58	pub const RBTDRM_COLOPHON_ONBOARD_PAYOR_HB: &str = "rbw-Op";
59	pub const RBTDRM_COLOPHON_ONBOARD_GOVERNOR_HB: &str = "rbw-Og";
60	// Windows group (4 of 5 — rbw-HWdw uses param1 channel, deferred to ₢A-AAS)
61	pub const RBTDRM_COLOPHON_HANDBOOK_TOP: &str = "rbw-h0";
62	pub const RBTDRM_COLOPHON_HANDBOOK_WINDOWS: &str = "rbw-hw";
63	pub const RBTDRM_COLOPHON_HW_DOCKER_DESKTOP: &str = "rbw-HWdd";
64	pub const RBTDRM_COLOPHON_HW_DOCKER_CONTEXT: &str = "rbw-HWdc";
65	// Payor group (3)
66	pub const RBTDRM_COLOPHON_PAYOR_ESTABLISH: &str = "rbw-gPE";
67	pub const RBTDRM_COLOPHON_PAYOR_REFRESH: &str = "rbw-gPR";
68	pub const RBTDRM_COLOPHON_QUOTA_BUILD: &str = "rbw-gq";
69	
70	// Fixture name consts — single definition per String Boundary Discipline.
71	// Crucible fixtures (charge/quench lifecycle)
72	pub const RBTDRM_FIXTURE_TADMOR: &str = "tadmor";
73	pub const RBTDRM_FIXTURE_SRJCL: &str = "srjcl";
74	pub const RBTDRM_FIXTURE_PLUML: &str = "pluml";
75	// Bare fixtures (GCP credentials, no container runtime)
76	pub const RBTDRM_FIXTURE_FOUR_MODE: &str = "four-mode";
77	pub const RBTDRM_FIXTURE_BATCH_VOUCH: &str = "batch-vouch";
78	pub const RBTDRM_FIXTURE_ACCESS_PROBE: &str = "access-probe";
79	// Fast fixtures (no external dependencies)
80	pub const RBTDRM_FIXTURE_ENROLLMENT_VALIDATION: &str = "enrollment-validation";
81	pub const RBTDRM_FIXTURE_REGIME_VALIDATION: &str = "regime-validation";
82	pub const RBTDRM_FIXTURE_REGIME_SMOKE: &str = "regime-smoke";
83	pub const RBTDRM_FIXTURE_HANDBOOK_RENDER: &str = "handbook-render";
84	
85	/// Per-fixture required colophons. Returns None for unknown fixtures.
86	pub fn rbtdrm_required_colophons(fixture: &str) -> Option<&'static [&'static str]> {
87	    match fixture {
88	        RBTDRM_FIXTURE_TADMOR | RBTDRM_FIXTURE_SRJCL | RBTDRM_FIXTURE_PLUML => Some(&[
89	            RBTDRM_COLOPHON_CHARGE,
90	            RBTDRM_COLOPHON_QUENCH,
91	            RBTDRM_COLOPHON_WRIT,
92	            RBTDRM_COLOPHON_FIAT,
93	            RBTDRM_COLOPHON_BARK,
94	            RBTDRM_COLOPHON_CRUCIBLE_ACTIVE,
95	        ]),
96	        RBTDRM_FIXTURE_FOUR_MODE => Some(&[
97	            RBTDRM_COLOPHON_ORDAIN,
98	            RBTDRM_COLOPHON_ABJURE,
99	            RBTDRM_COLOPHON_WREST,
100	            RBTDRM_COLOPHON_KLUDGE,
101	            RBTDRM_COLOPHON_SUMMON,
102	            RBTDRM_COLOPHON_PLUMB_FULL,
103	            RBTDRM_COLOPHON_PLUMB_COMPACT,
104	            RBTDRM_COLOPHON_REKON,
105	            RBTDRM_COLOPHON_JETTISON,
106	        ]),
107	        RBTDRM_FIXTURE_BATCH_VOUCH => Some(&[
108	            RBTDRM_COLOPHON_ORDAIN,
109	            RBTDRM_COLOPHON_ABJURE,
110	            RBTDRM_COLOPHON_JETTISON,
111	            RBTDRM_COLOPHON_VOUCH,
112	            RBTDRM_COLOPHON_TALLY,
113	        ]),
114	        RBTDRM_FIXTURE_ACCESS_PROBE => Some(&[RBTDRM_COLOPHON_ACCESS_PROBE]),
115	        RBTDRM_FIXTURE_ENROLLMENT_VALIDATION
116	        | RBTDRM_FIXTURE_REGIME_VALIDATION
117	        | RBTDRM_FIXTURE_REGIME_SMOKE => Some(&[]),
118	        RBTDRM_FIXTURE_HANDBOOK_RENDER => Some(&[
119	            RBTDRM_COLOPHON_ONBOARD_START_HERE,
120	            RBTDRM_COLOPHON_ONBOARD_CRASH_COURSE,
121	            RBTDRM_COLOPHON_ONBOARD_CRED_RETRIEVER,
122	            RBTDRM_COLOPHON_ONBOARD_CRED_DIRECTOR,
123	            RBTDRM_COLOPHON_ONBOARD_FIRST_CRUCIBLE,
124	            RBTDRM_COLOPHON_ONBOARD_DIR_FIRST_BUILD,
125	            RBTDRM_COLOPHON_ONBOARD_PAYOR_HB,
126	            RBTDRM_COLOPHON_ONBOARD_GOVERNOR_HB,
127	            RBTDRM_COLOPHON_HANDBOOK_TOP,
128	            RBTDRM_COLOPHON_HANDBOOK_WINDOWS,
129	            RBTDRM_COLOPHON_HW_DOCKER_DESKTOP,
130	            RBTDRM_COLOPHON_HW_DOCKER_CONTEXT,
131	            RBTDRM_COLOPHON_PAYOR_ESTABLISH,
132	            RBTDRM_COLOPHON_PAYOR_REFRESH,
133	            RBTDRM_COLOPHON_QUOTA_BUILD,
134	        ]),
135	        _ => None,
136	    }
137	}
138	
139	/// Verify that all required colophons for a fixture appear in the zipper manifest string.
140	pub fn rbtdrm_verify(manifest: &str, fixture: &str) -> Result<(), String> {
141	    let required = match rbtdrm_required_colophons(fixture) {
142	        Some(r) => r,
143	        None => {
144	            return Err(format!(
145	                "rbtd: unknown fixture '{}' — not registered in manifest",
146	                fixture
147	            ));
148	        }
149	    };
150	    for colophon in required {
151	        let found = manifest.split_whitespace().any(|token| token == *colophon);
152	        if !found {
153	            return Err(format!(
154	                "rbtd: colophon '{}' not found in zipper manifest (fixture '{}')",
155	                colophon, fixture
156	            ));
157	        }
158	    }
159	    Ok(())
160	}
161

